 1	import React, { FC, useMemo, useState } from 'react';
 2	
 3	import { modelToGroupVersionKind, PodModel, ServiceModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import { IoK8sApiCoreV1Pod, IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes';
 5	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getNamespace } from '@kubevirt-utils/resources/shared';
 8	import { getVMIPod } from '@kubevirt-utils/resources/vmi';
 9	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
10	import { Form, FormGroup, SelectList, SelectOption } from '@patternfly/react-core';
11	
12	import MultusNetwork from './Components/MultusNetwork';
13	import RDPConnector from './Components/RDPConnector';
14	import { MULTUS, POD } from './utils/constants';
15	import { DesktopViewerProps, Network } from './utils/types';
16	import { getDefaultNetwork, getRdpAddressPort, getVmRdpNetworks } from './utils/utils';
17	
18	const DesktopViewer: FC<DesktopViewerProps> = ({ vm, vmi }) => {
19	  const { t } = useKubevirtTranslation();
20	
21	  const networks = getVmRdpNetworks(vm, vmi);
22	  const [selectedNetwork, setSelectedNetwork] = useState<Network>(getDefaultNetwork(networks));
23	
24	  const [pods, podsLoaded] = useK8sWatchResource<IoK8sApiCoreV1Pod[]>({
25	    groupVersionKind: modelToGroupVersionKind(PodModel),
26	    isList: true,
27	    namespace: getNamespace(vm),
28	  });
29	
30	  const vmPod = useMemo(() => getVMIPod(vmi, pods), [vmi, pods]);
31	
32	  const [services, servicesLoaded] = useK8sWatchResource<IoK8sApiCoreV1Service[]>({
33	    groupVersionKind: modelToGroupVersionKind(ServiceModel),
34	    isList: true,
35	    namespace: getNamespace(vm),
36	  });
37	
38	  const rdpServiceAddressPort = getRdpAddressPort(vmi, services, vmPod);
39	  const networkType = selectedNetwork?.type;
40	
41	  const networkItems = networks?.map((network) => {
42	    return (
43	      <SelectOption
44	        onClick={() => {
45	          setSelectedNetwork(network);
46	        }}
47	        key={network?.name}
48	        value={network?.name}
49	      >
50	        {network?.name}
51	      </SelectOption>
52	    );
53	  });
54	
55	  return (
56	    <>
57	      <Form className="kv-vm-consoles__rdp-actions" isHorizontal>
58	        <FormGroup fieldId="network-dropdown" label={t('Network interface')}>
59	          <FormPFSelect
60	            id="network-dropdown"
61	            placeholder={t('--- Select network interface ---')}
62	            selected={selectedNetwork?.name}
63	            toggleProps={{ id: 'pf-v5-c-console__actions-desktop-toggle-id' }}
64	          >
65	            <SelectList>{networkItems}</SelectList>
66	          </FormPFSelect>
67	        </FormGroup>
68	      </Form>
69	      {networkType === POD && (
70	        <RDPConnector
71	          isLoading={!podsLoaded || !servicesLoaded}
72	          rdpServiceAddressPort={rdpServiceAddressPort}
73	          vm={vm}
74	          vmi={vmi}
75	        />
76	      )}
77	      {networkType === MULTUS && <MultusNetwork selectedNetwork={selectedNetwork} vmi={vmi} />}
78	    </>
79	  );
80	};
81	
82	export default DesktopViewer;

